      {confetti && (
        <div className="fixed inset-0 pointer-events-none z-[200]">
          {Array.from({ length: 40 }).map((_, i) => (
            <ConfettiParticle 
              key={`${confetti.id}-${i}`} 
              x={confetti.x} 
              y={confetti.y} 
              color={confettiColors[i % confettiColors.length]} 
            />
          ))}
        </div>
      )}

      {/* Play Management Modal */}
