              <button onClick={performReset} className="flex-1 py-3 bg-red-600 text-white rounded-xl font-bold">Yes, Reset</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-[#0c1a26] text-white shadow-xl py-6 sticky top-0 z-[100] border-b-4 border-amber-500">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center text-stone-900"><Trophy size={20}/></div>
            <div>
              <h1 className="text-2xl font-bold scrabble-font tracking-tight">LexiScore</h1>
              <p className="text-[8px] font-black text-amber-500 uppercase tracking-[0.3em]">Production Build</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleShare} className="p-2.5 bg-stone-800 rounded-xl text-stone-400 hover:text-white transition-colors" title="Share Leaderboard"><Share2 size={20}/></button>
            <button onClick={() => setIsResetModalOpen(true)} className="p-2.5 bg-stone-800 rounded-xl text-stone-400 hover:text-white transition-colors" title="Reset Game"><RotateCcw size={20}/></button>
            {!isGameStarted && <button onClick={addPlayer} className="p-2.5 bg-amber-600 rounded-xl text-stone-900 font-bold hover:bg-amber-500 transition-all"><UserPlus size={20}/></button>}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:grid lg:grid-cols-12 lg:gap-8 mt-4">
        {/* Main Scoreboard */}
        <div className="lg:col-span-8 space-y-6">
          <motion.div layout className="bg-[#0c1a26] rounded-[2rem] p-8 shadow-2xl border-b-8 border-amber-600 relative overflow-hidden">
            <div className="relative z-10 flex justify-between items-end">
              <div>
                <p className="text-amber-500 text-[10px] font-black uppercase tracking-[0.4em] mb-2">Turn Control</p>
                <h2 className="text-4xl font-bold text-white scrabble-font">{currentPlayer.name}</h2>
              </div>
              <div className="text-right">
                <p className="text-stone-500 text-[10px] font-black uppercase tracking-[0.4em] mb-2">Round</p>
                <p className="text-5xl font-black text-amber-500/10 tabular-nums">{gameRound.toString().padStart(2, '0')}</p>
              </div>
            </div>
            <div className="absolute top-0 right-0 h-full w-1/3 bg-gradient-to-l from-amber-500/5 to-transparent"></div>
          </motion.div>

          {/* Scores Table */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-stone-200 overflow-hidden">
            <div className="bg-stone-50 p-5 border-b border-stone-200 flex justify-between items-center">
              <span className="text-xs font-black text-stone-400 uppercase tracking-widest flex items-center gap-2"><ClipboardList size={16}/> Score Sheet</span>
              <span className="text-xs font-bold text-amber-600 bg-amber-100/50 px-3 py-1 rounded-full border border-amber-200">Current Turn Total: {roundTotal}</span>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-stone-100 text-[10px] text-stone-400 uppercase font-black">
                    <th className="px-4 py-4 text-center w-12 border-r border-stone-50">R#</th>
                    {players.map(p => (
                      <th key={p.id} className="px-8 py-4">{p.name}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-stone-50">
                  {Array.from({ length: gameRound }).map((_, rIdx) => (
                    <tr key={rIdx} className={`transition-colors ${rIdx === gameRound - 1 ? 'bg-amber-50/20' : 'hover:bg-stone-50/50'}`}>
                      <td className="px-2 py-6 text-center border-r border-stone-50 font-bold text-stone-300">{rIdx + 1}</td>
                      {players.map((p, pIdx) => {
                        const turn = p.turns[rIdx];
                        const isCurrentSlot = pIdx === currentPlayerIndex && rIdx === gameRound - 1;

                        return (
                          <td key={p.id} className="px-8 py-6 align-top">
                            {turn ? (
                              <div className="flex flex-col gap-2">
                                {turn.plays.map((play, playIdx) => (
                                  <button 
                                    key={playIdx}
                                    onClick={() => setSelectedPlayRef({ playerId: p.id, roundIdx: rIdx, playIdx, play })}
                                    className={`flex justify-between items-center p-2 rounded-xl transition-all group ${
                                      play.isRemoved ? 'opacity-20 line-through grayscale cursor-not-allowed' : 'hover:bg-white hover:shadow-md active:scale-95'
                                    }`}
                                  >
                                    <span className={`text-sm font-bold uppercase tracking-tight ${play.isBingo ? 'text-amber-800' : 'text-stone-800'}`}>
                                      {play.word}{play.isEdited ? '*' : ''}
                                      {play.isBingo && <Zap size={10} className="inline ml-1 text-amber-500 fill-current" />}
                                    </span>
                                    <span className={`text-[10px] font-black px-2 py-0.5 rounded-md ${play.isBingo ? 'bg-amber-500 text-white' : 'bg-stone-100 text-stone-500'}`}>
                                      {play.points}
                                    </span>
                                  </button>
                                ))}
                              </div>
                            ) : isCurrentSlot ? (
                              <motion.button 
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => setIsInputModalOpen(true)}
                                className="w-full py-4 border-2 border-dashed border-amber-300 rounded-2xl text-amber-500 flex flex-col items-center gap-1 hover:bg-amber-50 transition-all"
                              >
                                <Plus size={24}/>
                                <span className="text-[10px] font-black uppercase tracking-widest">Entry</span>
                              </motion.button>
                            ) : <span className="text-stone-200 text-xl font-light opacity-50">—</span>}
                          </td>
                        );
                      })}
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-[#0c1a26] text-white">
                   <tr>
                     <td className="p-6 border-r border-stone-800"></td>
                     {players.map(p => (
                       <td key={p.id} className="p-6 text-3xl font-bold scrabble-font text-amber-500">
                         {getPlayerStats(p).totalScore}
                       </td>
                     ))}
                   </tr>
                </tfoot>
              </table>
            </div>
          </div>
        </div>

        {/* Sidebar: Leaderboard */}
        <div className="lg:col-span-4 mt-8 lg:mt-0 space-y-6">
          <div className="bg-white rounded-[2rem] shadow-xl border border-stone-200 p-8">
            <h3 className="text-xs font-black text-stone-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
              <Trophy size={16} className="text-amber-500" /> Current Leaderboard
            </h3>
            <div className="space-y-4">
              {rankedPlayers.map(p => (
                <StatsCard 
                  key={p.id} 
                  name={p.name} 
                  isActive={p.id === currentPlayer.id} 
                  stats={getPlayerStats(p)} 
                />
              ))}
            </div>
          </div>

          <div className="bg-stone-800 rounded-[2rem] p-8 text-center text-white relative overflow-hidden">
            <p className="text-[10px] font-black uppercase text-stone-500 tracking-[0.4em] mb-4">Official Utility</p>
            <div className="flex items-center justify-center gap-3">
              <div className="w-10 h-10 bg-amber-500 rounded-2xl flex items-center justify-center font-bold text-[#0c1a26] text-xl">B</div>
              <span className="font-bold tracking-tight text-lg">BitDeserty Studios</span>
            </div>
            <div className="mt-6 flex justify-center gap-4 text-stone-500">
              <Info size={16}/>
              <span className="text-[10px] font-bold uppercase">v1.0.4 PRO</span>
            </div>
          </div>
        </div>
      </main>

      {/* Play Edit/Remove Modal */}
      <AnimatePresence>
        {selectedPlayRef && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-stone-900/90 backdrop-blur-md" onClick={() => setSelectedPlayRef(null)} />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative bg-white rounded-[2.5rem] shadow-2xl w-full max-w-sm overflow-hidden p-10 text-center">
              <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner">
                <Type size={40}/>
              </div>
              <h3 className="text-4xl font-bold scrabble-font mb-2 uppercase text-stone-900">{selectedPlayRef.play.word}</h3>
              <p className="text-stone-400 text-sm mb-10">Select an action for this entry</p>

              <div className="space-y-4">
                <button onClick={handleRemoveWord} className="w-full py-5 bg-red-50 hover:bg-red-100 text-red-600 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 transition-all active:scale-95">
                  <Trash2 size={20}/> Mark as Removed
                </button>
                <button onClick={() => setSelectedPlayRef(null)} className="w-full py-5 bg-stone-100 hover:bg-stone-200 text-stone-600 rounded-2xl font-black text-sm uppercase tracking-widest transition-all">Cancel</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { 
  RotateCcw, 
  SkipForward, 
  Info, 
  Pencil, 
  Check, 
  X, 
  UserPlus, 
  Trophy, 
  ClipboardList,
  Hash,
  AlertTriangle,
  Trash2,
  Zap,
  Type,
  Plus,
  Loader2,
  Search,
  Share2
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Player, PlayerStats, Play, GameSnapshot } from './types';
import StatsCard from './components/StatsCard';
import { defineWord } from './services/geminiService';
import { WORD_CHECKER } from './config';

const STORAGE_KEY = 'lexiscore_persistence_v1';

const App: React.FC = () => {
  // --- Initialization & Persistence ---
  const [players, setPlayers] = useState<Player[]>([
    { id: '1', name: 'Player 1', turns: [] },
    { id: '2', name: 'Player 2', turns: [] }
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameRound, setGameRound] = useState(1);
  const [isInitialized, setIsInitialized] = useState(false);

  // Load from Storage
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data: GameSnapshot = JSON.parse(saved);
        setPlayers(data.players);
        setCurrentPlayerIndex(data.currentPlayerIndex);
        setGameRound(data.gameRound);
      } catch (e) {
        console.error("Persistence Restore Failed", e);
      }
    }
    setIsInitialized(true);
  }, []);

  // Sync to Storage
  useEffect(() => {
    if (isInitialized) {
      const snapshot: GameSnapshot = { players, currentPlayerIndex, gameRound };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(snapshot));
    }
  }, [players, currentPlayerIndex, gameRound, isInitialized]);

  // --- UI State ---
  const [wordInput, setWordInput] = useState('');
  const [pointsInput, setPointsInput] = useState('');
  const [isBingoActive, setIsBingoActive] = useState(false);
  const [definition, setDefinition] = useState<string | null>(null);
  const [isLoadingDef, setIsLoadingDef] = useState(false);
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [isInputModalOpen, setIsInputModalOpen] = useState(false);

  const editInputRef = useRef<HTMLInputElement>(null);
  const [selectedPlayRef, setSelectedPlayRef] = useState<{ 
    playerId: string, 
    roundIdx: number, 
    playIdx: number,
    play: Play
  } | null>(null);
  const [editingPlayerId, setEditingPlayerId] = useState<string | null>(null);
  const [editNameValue, setEditNameValue] = useState('');

  // --- Derived State ---
  const getPlayerStats = useCallback((player: Player): PlayerStats => {
    let totalScore = 0;
    let allPlays: Play[] = [];
    player.turns.forEach(turn => {
      turn?.plays.forEach(play => {
        if (play.word !== '—' && !play.isRemoved) {
          totalScore += play.points;
          allPlays.push(play);
        }
      });
    });
    const wordCount = allPlays.length;
    const averagePoints = wordCount > 0 ? totalScore / wordCount : 0;
    const highestWord = allPlays.length > 0 
      ? [...allPlays].sort((a, b) => b.points - a.points)[0]
      : null;
    return { totalScore, averagePoints, highestWord, wordCount };
  }, []);

  const rankedPlayers = useMemo(() => {
    return [...players].sort((a, b) => getPlayerStats(b).totalScore - getPlayerStats(a).totalScore);
  }, [players, getPlayerStats]);

  const isGameStarted = useMemo(() => players.some(p => p.turns.length > 0), [players]);

  const legalityStatus = useMemo(() => {
    if (wordInput.trim().length < 2) return 'none';
    if (isLoadingDef) return 'loading';
    if (!definition) return 'none';
    if (definition.startsWith('ERROR')) return 'error';
    const verdict = definition.trim().toUpperCase();
    if (verdict.startsWith('VALID')) return 'legal';
    if (verdict.startsWith('INVALID')) return 'illegal';
    return 'none';
  }, [wordInput, isLoadingDef, definition]);

  // --- Handlers ---
  const handleVerifyWord = async () => {
    if (wordInput.trim().length < 2) return;
    setIsLoadingDef(true);
    const res = await defineWord(wordInput);
    setDefinition(res);
    setIsLoadingDef(false);
  };

  const submitWord = useCallback(() => {
    let points = parseInt(pointsInput);
    if (!wordInput.trim() || isNaN(points)) return;

    // Apply Bingo Bonus if active
    if (isBingoActive) points += 50;

    const roundIdx = gameRound - 1;
    const newPlay: Play = { 
      word: wordInput.trim().toUpperCase(), 
      points,
      isBingo: isBingoActive 
    };

    setPlayers(prev => {
      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];
      if (newTurns[roundIdx]) {
        const filtered = newTurns[roundIdx].plays.filter(p => p.word !== '—');
        newTurns[roundIdx] = { ...newTurns[roundIdx], plays: [...filtered, newPlay] };
      } else {
        newTurns[roundIdx] = { plays: [newPlay], timestamp: Date.now() };
      }
      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    setWordInput('');
    setPointsInput('');
    setIsBingoActive(false);
    setDefinition(null);
  }, [wordInput, pointsInput, currentPlayerIndex, gameRound, isBingoActive]);

  const endTurn = useCallback(() => {
    const roundIdx = gameRound - 1;
    setPlayers(prev => {
      if (prev[currentPlayerIndex].turns[roundIdx]) return prev;
      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];
      newTurns[roundIdx] = { plays: [{ word: '—', points: 0 }], timestamp: Date.now() };
      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    setIsInputModalOpen(false);
    if (currentPlayerIndex === players.length - 1) {
      setGameRound(prev => prev + 1);
    }
    setCurrentPlayerIndex(prev => (prev + 1) % players.length);
    setWordInput('');
    setPointsInput('');
    setIsBingoActive(false);
    setDefinition(null);
  }, [players.length, currentPlayerIndex, gameRound]);

  // Fix: Added handleRemoveWord to process removal requests for individual plays
  const handleRemoveWord = useCallback(() => {
    if (!selectedPlayRef) return;
    const { playerId, roundIdx, playIdx } = selectedPlayRef;

    setPlayers(prev => {
      return prev.map(p => {
        if (p.id !== playerId) return p;
        const newTurns = [...p.turns];
        if (newTurns[roundIdx]) {
          const newPlays = [...newTurns[roundIdx].plays];
          newPlays[playIdx] = { ...newPlays[playIdx], isRemoved: true };
          newTurns[roundIdx] = { ...newTurns[roundIdx], plays: newPlays };
        }
        return { ...p, turns: newTurns };
      });
    });

    setSelectedPlayRef(null);
  }, [selectedPlayRef]);

  const handleShare = async () => {
    const leader = rankedPlayers[0];
    const stats = getPlayerStats(leader);
    const text = `🏆 Scrabble Update - Round ${gameRound}\n1st: ${leader.name} (${stats.totalScore} pts)\n\nTracked with LexiScore.`;

    if (navigator.share) {
      try {
        await navigator.share({ title: 'LexiScore Update', text });
      } catch (e) {
        console.error("Share failed", e);
      }
    } else {
      await navigator.clipboard.writeText(text);
      alert("Scoreboard copied to clipboard!");
    }
  };

  const addPlayer = () => {
    if (isGameStarted) return;
    const newP = { id: Math.random().toString(36).substr(2, 9), name: `Player ${players.length + 1}`, turns: [] };
    setPlayers([...players, newP]);
  };

  const removePlayer = (id: string) => {
    if (isGameStarted || players.length <= 1) return;
    setPlayers(players.filter(p => p.id !== id));
    setCurrentPlayerIndex(0);
  };

  const performReset = () => {
    setPlayers(players.map(p => ({ ...p, turns: [] })));
    setCurrentPlayerIndex(0);
    setGameRound(1);
    setIsResetModalOpen(false);
    localStorage.removeItem(STORAGE_KEY);
  };

  const currentPlayer = players[currentPlayerIndex];
  const roundTotal = (currentPlayer.turns[gameRound - 1]?.plays || []).reduce((sum, p) => p.isRemoved ? sum : sum + p.points, 0);

  return (
    <div className="min-h-screen bg-stone-100 pb-12 font-sans selection:bg-amber-200">
      {/* Add Word Modal */}
      <AnimatePresence>
        {isInputModalOpen && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-stone-900/80 backdrop-blur-sm" onClick={() => setIsInputModalOpen(false)} />
            <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 50, opacity: 0 }} className="relative bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
              <div className="bg-[#0c1a26] p-8 text-white">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-amber-500 text-xs font-black uppercase tracking-widest">Entry Panel</h3>
                  <button onClick={() => setIsInputModalOpen(false)} className="text-stone-400 hover:text-white"><X size={20}/></button>
                </div>
                <div className="flex items-baseline gap-3">
                  <span className="text-4xl font-bold scrabble-font">{currentPlayer.name}</span>
                  <span className="text-stone-500 font-bold uppercase text-xs">R{gameRound}</span>
                </div>
              </div>

              <div className="p-8 space-y-6 overflow-y-auto flex-grow">
                <div className="space-y-2">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Word Played</label>
                    {WORD_CHECKER === 'AI' && wordInput.length >= 2 && (
                      <button 
                        onClick={handleVerifyWord} 
                        disabled={isLoadingDef}
                        className={`text-[10px] font-bold flex items-center gap-1 px-2 py-1 rounded-md transition-all ${
                          legalityStatus === 'legal' ? 'bg-green-100 text-green-700' : 
                          legalityStatus === 'illegal' ? 'bg-red-100 text-red-700' : 
                          'bg-amber-100 text-amber-700 active:scale-95'
                        }`}
                      >
                        {isLoadingDef ? <Loader2 size={10} className="animate-spin" /> : legalityStatus === 'legal' ? <Check size={10} /> : legalityStatus === 'illegal' ? <X size={10} /> : <Search size={10} />}
                        {legalityStatus === 'legal' ? 'Legal' : legalityStatus === 'illegal' ? 'Not Legal' : 'Check AI'}
                      </button>
                    )}
                  </div>
                  <input 
                    autoFocus
                    type="text" 
                    value={wordInput}
                    onChange={e => {setWordInput(e.target.value.toUpperCase()); setDefinition(null);}}
                    className="w-full text-3xl font-black p-4 bg-stone-50 border-2 border-stone-200 rounded-2xl outline-none focus:border-amber-500 uppercase transition-colors"
                    placeholder="..."
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest px-1">Points</label>
                    <input 
                      type="number" 
                      inputMode="numeric"
                      value={pointsInput}
                      onChange={e => setPointsInput(e.target.value)}
                      className="w-full text-3xl font-black p-4 bg-stone-50 border-2 border-stone-200 rounded-2xl outline-none focus:border-amber-500"
                      placeholder="0"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest px-1">Bonus</label>
                    <button 
                      onClick={() => setIsBingoActive(!isBingoActive)}
                      className={`w-full h-[76px] rounded-2xl border-2 flex items-center justify-center gap-2 font-black transition-all ${isBingoActive ? 'bg-amber-500 border-amber-600 text-stone-900 shadow-inner' : 'bg-stone-50 border-stone-200 text-stone-400'}`}
                    >
                      <Zap size={20} className={isBingoActive ? 'fill-current' : ''} />
                      BINGO
                    </button>
                  </div>
                </div>

                {definition && (
                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-4 bg-stone-50 rounded-xl border border-stone-200 text-sm text-stone-600 italic">
                    {definition.replace(/^(VALID|INVALID|ERROR)\s*:\s*/i, '')}
                  </motion.div>
                )}
              </div>

              <div className="p-8 bg-stone-50 border-t border-stone-100 flex gap-4">
                <button onClick={submitWord} disabled={!wordInput || !pointsInput} className="flex-1 bg-amber-600 hover:bg-amber-500 disabled:bg-stone-200 text-stone-900 py-4 rounded-2xl font-black text-lg shadow-lg active:scale-95 transition-all">ADD WORD</button>
                <button onClick={endTurn} className="flex-1 bg-[#0c1a26] hover:bg-black text-amber-500 py-4 rounded-2xl font-black text-lg active:scale-95 transition-all">END TURN</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Persistence Reset Modal */}
      {isResetModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-3xl max-w-sm w-full text-center shadow-2xl">
            <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32}/>
            </div>
            <h3 className="text-2xl font-bold mb-2">Clear Game?</h3>
            <p className="text-stone-500 mb-8 text-sm">This will permanently delete all scores. Use "Share" first if you want to save the final standings.</p>
            <div className="flex gap-4">
              <button onClick={() => setIsResetModalOpen(false)} className="flex-1 py-3 bg-stone-100 rounded-xl font-bold">Cancel</button>
              <button onClick={performReset} className="flex-1 py-3 bg-red-600 text-white rounded-xl font-bold">Yes, Reset</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-[#0c1a26] text-white shadow-xl py-6 sticky top-0 z-[100] border-b-4 border-amber-500">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center text-stone-900"><Trophy size={20}/></div>
            <div>
              <h1 className="text-2xl font-bold scrabble-font tracking-tight">LexiScore</h1>
              <p className="text-[8px] font-black text-amber-500 uppercase tracking-[0.3em]">Production Build</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleShare} className="p-2.5 bg-stone-800 rounded-xl text-stone-400 hover:text-white transition-colors" title="Share Leaderboard"><Share2 size={20}/></button>
            <button onClick={() => setIsResetModalOpen(true)} className="p-2.5 bg-stone-800 rounded-xl text-stone-400 hover:text-white transition-colors" title="Reset Game"><RotateCcw size={20}/></button>
            {!isGameStarted && <button onClick={addPlayer} className="p-2.5 bg-amber-600 rounded-xl text-stone-900 font-bold hover:bg-amber-500 transition-all"><UserPlus size={20}/></button>}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:grid lg:grid-cols-12 lg:gap-8 mt-4">
        {/* Main Scoreboard */}
        <div className="lg:col-span-8 space-y-6">
          <motion.div layout className="bg-[#0c1a26] rounded-[2rem] p-8 shadow-2xl border-b-8 border-amber-600 relative overflow-hidden">
            <div className="relative z-10 flex justify-between items-end">
              <div>
                <p className="text-amber-500 text-[10px] font-black uppercase tracking-[0.4em] mb-2">Turn Control</p>
                <h2 className="text-4xl font-bold text-white scrabble-font">{currentPlayer.name}</h2>
              </div>
              <div className="text-right">
                <p className="text-stone-500 text-[10px] font-black uppercase tracking-[0.4em] mb-2">Round</p>
                <p className="text-5xl font-black text-amber-500/10 tabular-nums">{gameRound.toString().padStart(2, '0')}</p>
              </div>
            </div>
            <div className="absolute top-0 right-0 h-full w-1/3 bg-gradient-to-l from-amber-500/5 to-transparent"></div>
          </motion.div>

          {/* Scores Table */}
          <div className="bg-white rounded-[2rem] shadow-xl border border-stone-200 overflow-hidden">
            <div className="bg-stone-50 p-5 border-b border-stone-200 flex justify-between items-center">
              <span className="text-xs font-black text-stone-400 uppercase tracking-widest flex items-center gap-2"><ClipboardList size={16}/> Score Sheet</span>
              <span className="text-xs font-bold text-amber-600 bg-amber-100/50 px-3 py-1 rounded-full border border-amber-200">Current Turn Total: {roundTotal}</span>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-stone-100 text-[10px] text-stone-400 uppercase font-black">
                    <th className="px-4 py-4 text-center w-12 border-r border-stone-50">R#</th>
                    {players.map(p => (
                      <th key={p.id} className="px-8 py-4">{p.name}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-stone-50">
                  {Array.from({ length: gameRound }).map((_, rIdx) => (
                    <tr key={rIdx} className={`transition-colors ${rIdx === gameRound - 1 ? 'bg-amber-50/20' : 'hover:bg-stone-50/50'}`}>
                      <td className="px-2 py-6 text-center border-r border-stone-50 font-bold text-stone-300">{rIdx + 1}</td>
                      {players.map((p, pIdx) => {
                        const turn = p.turns[rIdx];
                        const isCurrentSlot = pIdx === currentPlayerIndex && rIdx === gameRound - 1;

                        return (
                          <td key={p.id} className="px-8 py-6 align-top">
                            {turn ? (
                              <div className="flex flex-col gap-2">
                                {turn.plays.map((play, playIdx) => (
                                  <button 
                                    key={playIdx}
                                    onClick={() => setSelectedPlayRef({ playerId: p.id, roundIdx: rIdx, playIdx, play })}
                                    className={`flex justify-between items-center p-2 rounded-xl transition-all group ${
                                      play.isRemoved ? 'opacity-20 line-through grayscale cursor-not-allowed' : 'hover:bg-white hover:shadow-md active:scale-95'
                                    }`}
                                  >
                                    <span className={`text-sm font-bold uppercase tracking-tight ${play.isBingo ? 'text-amber-800' : 'text-stone-800'}`}>
                                      {play.word}{play.isEdited ? '*' : ''}
                                      {play.isBingo && <Zap size={10} className="inline ml-1 text-amber-500 fill-current" />}
                                    </span>
                                    <span className={`text-[10px] font-black px-2 py-0.5 rounded-md ${play.isBingo ? 'bg-amber-500 text-white' : 'bg-stone-100 text-stone-500'}`}>
                                      {play.points}
                                    </span>
                                  </button>
                                ))}
                              </div>
                            ) : isCurrentSlot ? (
                              <motion.button 
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => setIsInputModalOpen(true)}
                                className="w-full py-4 border-2 border-dashed border-amber-300 rounded-2xl text-amber-500 flex flex-col items-center gap-1 hover:bg-amber-50 transition-all"
                              >
                                <Plus size={24}/>
                                <span className="text-[10px] font-black uppercase tracking-widest">Entry</span>
                              </motion.button>
                            ) : <span className="text-stone-200 text-xl font-light opacity-50">—</span>}
                          </td>
                        );
                      })}
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-[#0c1a26] text-white">
                   <tr>
                     <td className="p-6 border-r border-stone-800"></td>
                     {players.map(p => (
                       <td key={p.id} className="p-6 text-3xl font-bold scrabble-font text-amber-500">
                         {getPlayerStats(p).totalScore}
                       </td>
                     ))}
                   </tr>
                </tfoot>
              </table>
            </div>
          </div>
        </div>

        {/* Sidebar: Leaderboard */}
        <div className="lg:col-span-4 mt-8 lg:mt-0 space-y-6">
          <div className="bg-white rounded-[2rem] shadow-xl border border-stone-200 p-8">
            <h3 className="text-xs font-black text-stone-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
              <Trophy size={16} className="text-amber-500" /> Current Leaderboard
            </h3>
            <div className="space-y-4">
              {rankedPlayers.map(p => (
                <StatsCard 
                  key={p.id} 
                  name={p.name} 
                  isActive={p.id === currentPlayer.id} 
                  stats={getPlayerStats(p)} 
                />
              ))}
            </div>
          </div>

          <div className="bg-stone-800 rounded-[2rem] p-8 text-center text-white relative overflow-hidden">
            <p className="text-[10px] font-black uppercase text-stone-500 tracking-[0.4em] mb-4">Official Utility</p>
            <div className="flex items-center justify-center gap-3">
              <div className="w-10 h-10 bg-amber-500 rounded-2xl flex items-center justify-center font-bold text-[#0c1a26] text-xl">B</div>
              <span className="font-bold tracking-tight text-lg">BitDeserty Studios</span>
            </div>
            <div className="mt-6 flex justify-center gap-4 text-stone-500">
              <Info size={16}/>
              <span className="text-[10px] font-bold uppercase">v1.0.4 PRO</span>
            </div>
          </div>
        </div>
      </main>

      {/* Play Edit/Remove Modal */}
      <AnimatePresence>
        {selectedPlayRef && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-stone-900/90 backdrop-blur-md" onClick={() => setSelectedPlayRef(null)} />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative bg-white rounded-[2.5rem] shadow-2xl w-full max-w-sm overflow-hidden p-10 text-center">
              <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner">
                <Type size={40}/>
              </div>
              <h3 className="text-4xl font-bold scrabble-font mb-2 uppercase text-stone-900">{selectedPlayRef.play.word}</h3>
              <p className="text-stone-400 text-sm mb-10">Select an action for this entry</p>

              <div className="space-y-4">
                <button onClick={handleRemoveWord} className="w-full py-5 bg-red-50 hover:bg-red-100 text-red-600 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 transition-all active:scale-95">
                  <Trash2 size={20}/> Mark as Removed
                </button>
                <button onClick={() => setSelectedPlayRef(null)} className="w-full py-5 bg-stone-100 hover:bg-stone-200 text-stone-600 rounded-2xl font-black text-sm uppercase tracking-widest transition-all">Cancel</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;
